UPDATE words SET example_en_2 = 'Students collaborate to complete research projects.', example_ko_2 = '학생들은 연구 프로젝트를 완성하기 위해 협력해요.', example_en_3 = 'She collaborated with a professor from another university.', example_ko_3 = '그녀는 다른 대학교의 교수와 협력했어요.', example_en_4 = 'Collaborating across disciplines leads to better outcomes.', example_ko_4 = '학문 분야를 넘나들어 협력하면 더 나은 결과로 이어져요.', example_en_5 = 'They collaborated on a paper published in a top journal.', example_ko_5 = '그들은 유명 학술지에 게재된 논문을 함께 썼어요.' WHERE id = 'w_education_B2_24';
UPDATE words SET example_en_2 = 'She updated her curriculum vitae before applying for the job.', example_ko_2 = '그녀는 취업 지원 전에 이력서를 업데이트했어요.', example_en_3 = 'A curriculum vitae lists your academic and work history.', example_ko_3 = '이력서는 학력과 경력 사항을 나열해요.', example_en_4 = 'Tailor your curriculum vitae to each application.', example_ko_4 = '각 지원서에 맞게 이력서를 조정하세요.', example_en_5 = 'A strong curriculum vitae highlights your key achievements.', example_ko_5 = '훌륭한 이력서는 주요 성과를 강조해요.' WHERE id = 'w_education_B2_25';
UPDATE words SET example_en_2 = 'The bibliography lists all sources used in the paper.', example_ko_2 = '참고 문헌 목록은 논문에 사용된 모든 출처를 나열해요.', example_en_3 = 'Please format the bibliography in APA style.', example_ko_3 = '참고 문헌 목록을 APA 형식으로 작성해 주세요.', example_en_4 = 'She checked the bibliography for missing entries.', example_ko_4 = '그녀는 참고 문헌 목록에서 누락된 항목을 확인했어요.', example_en_5 = 'An accurate bibliography strengthens your academic work.', example_ko_5 = '정확한 참고 문헌 목록은 학문적 작업을 강화해요.' WHERE id = 'w_education_B2_26';
UPDATE words SET example_en_2 = 'The syllabus outlines the course objectives and schedule.', example_ko_2 = '강의 계획서는 과목 목표와 일정을 설명해요.', example_en_3 = 'Please read the syllabus before the first class.', example_ko_3 = '첫 수업 전에 강의 계획서를 읽어 주세요.', example_en_4 = 'The syllabus includes the grading breakdown.', example_ko_4 = '강의 계획서에는 성적 산출 방식이 포함돼요.', example_en_5 = 'She referred to the syllabus to plan her study schedule.', example_ko_5 = '그녀는 학습 일정을 계획하기 위해 강의 계획서를 참고했어요.' WHERE id = 'w_education_B2_27';
UPDATE words SET example_en_2 = 'He received tenure after years of dedicated research.', example_ko_2 = '그는 수년간의 헌신적인 연구 끝에 종신 재직권을 받았어요.', example_en_3 = 'Tenure provides professors with long-term job security.', example_ko_3 = '종신 재직권은 교수들에게 장기적인 고용 안정을 제공해요.', example_en_4 = 'The path to tenure requires publishing and teaching.', example_ko_4 = '종신 재직권을 얻는 길에는 논문 출간과 강의가 필요해요.', example_en_5 = 'She is on track to receive tenure next year.', example_ko_5 = '그녀는 내년에 종신 재직권을 받을 예정이에요.' WHERE id = 'w_education_B2_28';
UPDATE words SET example_en_2 = 'The university received full accreditation this year.', example_ko_2 = '그 대학교는 올해 완전한 인가를 받았어요.', example_en_3 = 'Accreditation ensures a program meets quality standards.', example_ko_3 = '인가는 프로그램이 품질 기준을 충족하는지 보장해요.', example_en_4 = 'She checked the accreditation status before enrolling.', example_ko_4 = '그녀는 등록하기 전에 인가 상태를 확인했어요.', example_en_5 = 'Loss of accreditation can seriously harm a school''s reputation.', example_ko_5 = '인가 취소는 학교의 명성에 심각한 영향을 줄 수 있어요.' WHERE id = 'w_education_B2_29';
UPDATE words SET example_en_2 = 'Request your official transcript from the registrar.', example_ko_2 = '학사 담당 사무실에 공식 성적 증명서를 요청하세요.', example_en_3 = 'The transcript showed all courses and grades.', example_ko_3 = '성적 증명서에는 모든 과목과 성적이 나타나 있었어요.', example_en_4 = 'Graduate schools often require an official transcript.', example_ko_4 = '대학원은 종종 공식 성적 증명서를 요구해요.', example_en_5 = 'She sent her transcript along with the application.', example_ko_5 = '그녀는 지원서와 함께 성적 증명서를 보냈어요.' WHERE id = 'w_education_B2_30';
UPDATE words SET example_en_2 = 'She applied for a research grant to fund her project.', example_ko_2 = '그녀는 프로젝트를 위한 연구 보조금을 신청했어요.', example_en_3 = 'The grant covered all laboratory expenses.', example_ko_3 = '보조금이 모든 실험실 비용을 충당했어요.', example_en_4 = 'Winning a grant is highly competitive.', example_ko_4 = '보조금을 받는 것은 경쟁이 매우 치열해요.', example_en_5 = 'He used the grant to travel to a conference abroad.', example_ko_5 = '그는 보조금을 사용하여 해외 학회에 참석했어요.' WHERE id = 'w_education_B2_31';
UPDATE words SET example_en_2 = 'The cohort completed the program together over two years.', example_ko_2 = '그 코호트는 2년에 걸쳐 프로그램을 함께 완료했어요.', example_en_3 = 'Her cohort was the largest in the program''s history.', example_ko_3 = '그녀의 코호트는 그 프로그램 역사상 가장 규모가 컸어요.', example_en_4 = 'The study tracked a cohort of students over five years.', example_ko_4 = '그 연구는 5년에 걸쳐 학생 코호트를 추적했어요.', example_en_5 = 'Being part of a cohort fosters a strong sense of community.', example_ko_5 = '코호트의 일원이 되면 강한 공동체 의식이 생겨요.' WHERE id = 'w_education_B2_32';
UPDATE words SET example_en_2 = 'The project took an interdisciplinary approach to climate change.', example_ko_2 = '그 프로젝트는 기후 변화에 학제간 접근법을 취했어요.', example_en_3 = 'Interdisciplinary research combines different fields of study.', example_ko_3 = '학제간 연구는 다양한 학문 분야를 결합해요.', example_en_4 = 'She enjoyed the interdisciplinary nature of her program.', example_ko_4 = '그녀는 자신의 프로그램의 학제간 성격을 즐겼어요.', example_en_5 = 'Interdisciplinary teams often find more creative solutions.', example_ko_5 = '학제간 팀은 종종 더 창의적인 해결책을 찾아요.' WHERE id = 'w_education_B2_33';
UPDATE words SET example_en_2 = 'Statistics is a prerequisite for the research methods course.', example_ko_2 = '통계학은 연구 방법론 수업의 선수 과목이에요.', example_en_3 = 'Make sure you meet all prerequisites before enrolling.', example_ko_3 = '등록하기 전에 모든 선수 과목 요건을 충족하는지 확인하세요.', example_en_4 = 'The prerequisite was waived for experienced students.', example_ko_4 = '경험 있는 학생들에게는 선수 과목이 면제됐어요.', example_en_5 = 'Without the prerequisite, the course may be too difficult.', example_ko_5 = '선수 과목 없이는 그 과목이 너무 어려울 수 있어요.' WHERE id = 'w_education_B2_34';
UPDATE words SET example_en_2 = 'She wrote her thesis on progressive pedagogy.', example_ko_2 = '그녀는 진보적 교육학에 관한 논문을 썼어요.', example_en_3 = 'Good pedagogy adapts to the needs of learners.', example_ko_3 = '좋은 교육학은 학습자의 필요에 맞게 적응해요.', example_en_4 = 'The course explored the pedagogy of language teaching.', example_ko_4 = '그 과목은 언어 교수의 교육학을 탐구했어요.', example_en_5 = 'Effective pedagogy motivates students to learn independently.', example_ko_5 = '효과적인 교육학은 학생들이 스스로 학습하도록 동기를 부여해요.' WHERE id = 'w_education_B2_35';
